class Solution {
    public int countNumbers(String l, String r, int b) {
        long numL = Long.parseLong(l, b);
        long numR = Long.parseLong(r, b);
        int MOD = (int) (1e9 + 7);
        int maxLen = r.length();
        long[][] dp = new long[maxLen + 1][b];
        for (int i = 0; i < b; i++) {
            dp[1][i] = 1;
        }
        for (int i = 2; i <= maxLen; i++) {
            for (int j = 0; j < b; j++) {
                for (int k = 0; k <= j; k++) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][k]) % MOD;
                }
            }
        }
        long count = 0;
        int len = r.length();
        int[] digits = new int[len];
        for (int i = 0; i < len; i++) {
            digits[i] = Character.digit(r.charAt(i), b);
        }
        int lastDigit = 0;
        for (int i = 0; i < len; i++) {
            for (int j = lastDigit; j < digits[i]; j++) {
                count = (count + dp[len - i - 1][j]) % MOD;
            }
            if (digits[i] < lastDigit) {
                break;
            }
            lastDigit = digits[i];
            if (i == len - 1) {
                count = (count + 1) % MOD;
            }
        }
        len = l.length();
        digits = new int[len];
        for (int i = 0; i < len; i++) {
            digits[i] = Character.digit(l.charAt(i), b);
        }
        lastDigit = 0;
        long countL = 0;
        for (int i = 0; i < len; i++) {
            for (int j = lastDigit; j < digits[i]; j++) {
                countL = (countL + dp[len - i - 1][j]) % MOD;
            }
            if (digits[i] < lastDigit) {
                break;
            }
            lastDigit = digits[i];
            if (i == len - 1) {
                countL = (countL + 1) % MOD;
            }
        }
        return (int) ((count - countL + (numL <= numR ? 1 : 0)) % MOD);
    }
}
